// ── CSS injected once ────────────────────────────────────────
(function _injectStampCSS() {
  if (document.getElementById('_stamp_css')) return;
  const s = document.createElement('style');
  s.id = '_stamp_css';
  s.textContent = `
    .efed-moodlet { image-rendering: auto; flex-shrink: 0; vertical-align: middle; }
    .moodlet-picker-btn {
      background: none; border: 1px solid rgba(255,255,255,.12); border-radius: 8px;
      padding: 5px 6px; cursor: pointer; transition: background .15s, transform .1s;
      display: inline-flex; align-items: center; justify-content: center;
    }
    .moodlet-picker-btn:hover { background: rgba(255,255,255,.1); transform: scale(1.12); }
  `;
  document.head.appendChild(s);
})();

