// ── eFed EMOJI POOL (random-seed per eFed name) ──────────────
function getEfedEmojis(name) {
  const POOLS = [
    ['👍','✅','💪','🙌','👏','🤜','🫡','🤝','💯','👆','🫶','🔥'],
    ['👎','❌','🚫','😤','🤦','🙄','🫵','😒','🖐️','✋'],
    ['😂','🤣','😄','🥲','😆','😁','😍','😝','🤪','😜','🎭'],
    ['😢','😔','💔','😞','🥺','😩','🤕','😭','🫀','🩹'],
    ['🎉','🏆','🎊','👑','🥳','🥇','⭐','🎖️','💫','🎺','🔔','🤩'],
    ['⚡','💥','👊','💢','🩸','😡','🥊','🦾','🤬','😤'],
    ['🗑️','🤡','💩','🥴','😬','🫤','🤮','😒'],
    ['💎','🕳️','🌪️','🔑','🖼️','🎯','📺','🪑','🔗','⛓️','🪓','🎩'],
    ['😱','🤯','👀','😳','🫣','😲','😮','🫨','🙀','😦'],
    ['😈','💀','🖤','😏','🔱','🕷️','👹','🦇','☠️','🗡️'],
  ];
  let seed = 0;
  for (let i = 0; i < (name||'').length; i++) seed = ((seed * 31 + name.charCodeAt(i)) >>> 0);
  const _set = POOLS.map((pool, i) => pool[(seed >>> (i * 3)) % pool.length]);
  try {
    const _s = JSON.parse(localStorage.getItem('efed_session'));
    if (_s && (_s.username||'').toLowerCase() === 'derrick_maximus') _set.push('🎲');
  } catch(e) {}
  return _set;
}

