// ── STAMP HELPER FUNCTIONS ───────────────────────────────────

/** Get a stamp by code */
function getStamp(code) {
  return STAMP_DEFS.find(s => s.code === code) || null;
}

/** Get all stamps in a category (1–10) */
function getStampsByCategory(cat) {
  return STAMP_DEFS.filter(s => s.cat === cat);
}

/**
 * Assign one stamp per category to an eFed, seeded by name.
 * Returns array of 10 stamp objects (one per category).
 */
function getEfedStamps(name) {
  if (!name) name = '';
  let seed = 0;
  for (let i = 0; i < name.length; i++) seed = ((seed * 31 + name.charCodeAt(i)) >>> 0);
  const stamps = [];
  for (let cat = 1; cat <= 10; cat++) {
    const pool = getStampsByCategory(cat);
    if (pool.length) stamps.push(pool[(seed >>> (cat * 2)) % pool.length]);
  }
  return stamps;
}

/** Render a stamp as an inline <img> */
function stampImg(code, size) {
  const s = getStamp(code);
  if (!s) return '';
  const url = 'data:image/svg+xml;base64,' + btoa(unescape(encodeURIComponent(s.svg)));
  return `<img src="${url}" width="${size||24}" height="${size||24}" class="efed-moodlet" title="${s.label}" style="display:inline-block;vertical-align:middle;margin:0 2px;">`;
}

/** Replace [m:code] tokens in already-escaped HTML text */
function renderStampTokens(escapedText) {
  if (!escapedText || !escapedText.includes('[m:')) return escapedText;
  return escapedText.replace(/\[m:([a-z0-9_]+)\]/g, (_, code) => stampImg(code, 24));
}

/** Insert [m:code] token at cursor in a text input/textarea */
function insertStampAtCursor(inputEl, code) {
  if (!inputEl) return;
  const token = '[m:' + code + '] ';
  const s = inputEl.selectionStart, e = inputEl.selectionEnd, v = inputEl.value;
  inputEl.value = v.slice(0, s) + token + v.slice(e);
  inputEl.selectionStart = inputEl.selectionEnd = s + token.length;
  inputEl.focus();
}

// ── BACKWARDS COMPAT ALIASES ─────────────────────────────────
// Old code that calls _moodletImg / _renderWithMoodlets still works
const _moodletImg = stampImg;
const _renderWithMoodlets = renderStampTokens;
const _insertMoodletAtCursor = insertStampAtCursor;
const MOODLET_DEFS = STAMP_DEFS;
function _getMoodletForEfed(name) {
  // legacy: returns single stamp for the eFed (cat 1 only, seeded)
  const pool = getStampsByCategory(1);
  let seed = 0;
  for (let i = 0; i < (name||'').length; i++) seed = ((seed * 31 + name.charCodeAt(i)) >>> 0);
  return pool[seed % pool.length];
}
